"use client";

import "@getpara/react-sdk/styles.css";

import {
  createContext,
  useContext,
  useEffect,
  useMemo,
  useState,
  type ReactNode,
} from "react";
import ParaWeb, {
  Environment,
  ParaProvider,
  useAccount as useParaAccount,
  useClient,
  useModal,
  type TOAuthMethod,
  type TExternalWallet,
} from "@getpara/react-sdk";
import { CoreStoreContext } from "@getpara/react-core/internal";
import { createParaWagmiConfig } from "@getpara/evm-wallet-connectors";
import { QueryClient, QueryClientProvider } from "@tanstack/react-query";
import {
  useAccount,
  useSendTransaction,
  useSignTypedData,
  useSwitchChain,
  WagmiProvider,
  createConfig,
} from "wagmi";
import {
  mainnet,
  arbitrum,
  optimism,
  base,
  polygon,
  sepolia,
  linea,
  lineaSepolia,
} from "wagmi/chains";
import { defineChain, http, type Chain, type Transport } from "viem";
import {
  toViemSignTypedDataArgs,
  type WalletEip712Payload,
  type WalletTxPayload,
} from "@aomi-labs/react";
import type { AccountIdentity } from "@/lib/account-identity";

export type AomiAdapter = {
  identity: AccountIdentity;
  isReady: boolean;
  isSwitchingChain: boolean;
  canConnect: boolean;
  canManageAccount: boolean;
  connect: () => Promise<void>;
  manageAccount: () => Promise<void>;
  switchChain?: (chainId: number) => Promise<void>;
  sendTransaction?: (
    payload: WalletTxPayload,
  ) => Promise<{ txHash: string; amount?: string }>;
  signTypedData?: (
    payload: WalletEip712Payload,
  ) => Promise<{ signature: string }>;
};

type AomiAdapterProviderProps = {
  children: ReactNode;
  adapter?: AomiAdapter | null;
};

const useLocalhost = process.env.NEXT_PUBLIC_USE_LOCALHOST === "true";
const LOCALHOST_CHAIN_ID = 31337;
const paraApiKey = process.env.NEXT_PUBLIC_PARA_API_KEY;
const walletConnectProjectId =
  process.env.NEXT_PUBLIC_WALLETCONNECT_PROJECT_ID ||
  process.env.NEXT_PUBLIC_PROJECT_ID;
const paraEnvironment =
  (process.env.NEXT_PUBLIC_PARA_ENVIRONMENT as Environment | undefined) ??
  Environment.BETA;

const localhost = defineChain({
  id: LOCALHOST_CHAIN_ID,
  name: "Localhost",
  nativeCurrency: {
    decimals: 18,
    name: "Ether",
    symbol: "ETH",
  },
  rpcUrls: {
    default: {
      http: ["http://127.0.0.1:8545"],
    },
  },
  blockExplorers: {
    default: {
      name: "Local",
      url: "http://127.0.0.1:8545",
    },
  },
});

const defaultNetworks = [
  mainnet,
  arbitrum,
  optimism,
  base,
  polygon,
  sepolia,
  linea,
  lineaSepolia,
] as const;

const networks = (useLocalhost
  ? [localhost, ...defaultNetworks]
  : [...defaultNetworks]) as readonly [Chain, ...Chain[]];

const transports = Object.fromEntries(
  networks.map((network) => [network.id, http(network.rpcUrls.default.http[0])]),
) as Record<number, Transport>;

const externalWallets: TExternalWallet[] = [
  "WALLETCONNECT",
  "METAMASK",
  "COINBASE",
  "RAINBOW",
  "RABBY",
];

const oAuthMethods: TOAuthMethod[] = ["GOOGLE"];

const ssrFallbackConfig = createConfig({
  chains: networks,
  transports,
  ssr: true,
});

const DISCONNECTED_ADAPTER: AomiAdapter = {
  identity: {
    kind: "disconnected",
    isConnected: false,
    address: undefined,
    chainId: undefined,
    authProvider: undefined,
    primaryLabel: "Not connected",
    secondaryLabel: undefined,
  },
  isReady: false,
  isSwitchingChain: false,
  canConnect: false,
  canManageAccount: false,
  connect: async () => undefined,
  manageAccount: async () => undefined,
};

const AomiAdapterContext = createContext<AomiAdapter>(DISCONNECTED_ADAPTER);

function parseChainId(value: unknown): number | undefined {
  if (typeof value === "number" && Number.isFinite(value)) return value;
  if (typeof value !== "string") return undefined;
  const trimmed = value.trim();
  if (trimmed.startsWith("0x")) {
    const parsedHex = Number.parseInt(trimmed.slice(2), 16);
    return Number.isFinite(parsedHex) ? parsedHex : undefined;
  }
  const parsed = Number.parseInt(trimmed, 10);
  return Number.isFinite(parsed) ? parsed : undefined;
}

function formatAddress(address?: string): string | undefined {
  if (!address) return undefined;
  return `${address.slice(0, 5)}..${address.slice(-2)}`;
}

function formatAuthProvider(provider?: string): string | undefined {
  if (!provider) return undefined;

  const labelMap: Record<string, string> = {
    google: "Google",
    github: "GitHub",
    apple: "Apple",
    facebook: "Facebook",
    x: "X",
    discord: "Discord",
    farcaster: "Farcaster",
    telegram: "Telegram",
    email: "Email",
    phone: "Phone",
    wallet: "Wallet",
  };

  return labelMap[provider] ?? provider;
}

function inferAuthProvider(authMethods: unknown): string | undefined {
  if (!(authMethods instanceof Set) || authMethods.size === 0) return undefined;

  const allowed = new Set([
    "google",
    "github",
    "apple",
    "facebook",
    "x",
    "discord",
    "farcaster",
    "telegram",
    "email",
    "phone",
  ]);

  for (const method of authMethods) {
    if (typeof method !== "string") continue;
    const normalized = method.toLowerCase();
    if (allowed.has(normalized)) return normalized;
  }

  const first = authMethods.values().next().value;
  return typeof first === "string" ? first.toLowerCase() : undefined;
}

function LocalhostNetworkEnforcer({ children }: { children: ReactNode }) {
  const { isConnected, chainId, connector } = useAccount();
  const { switchChain } = useSwitchChain();

  useEffect(() => {
    if (!useLocalhost) return;
    if (!isConnected || chainId === LOCALHOST_CHAIN_ID) return;

    void (async () => {
      try {
        const provider = await connector?.getProvider();
        if (provider && typeof provider === "object" && "request" in provider) {
          const ethProvider = provider as {
            request: (args: { method: string; params: unknown[] }) => Promise<unknown>;
          };
          try {
            await ethProvider.request({
              method: "wallet_addEthereumChain",
              params: [
                {
                  chainId: `0x${LOCALHOST_CHAIN_ID.toString(16)}`,
                  chainName: "Localhost",
                  nativeCurrency: {
                    name: "Ether",
                    symbol: "ETH",
                    decimals: 18,
                  },
                  rpcUrls: ["http://127.0.0.1:8545"],
                },
              ],
            });
          } catch {
            // Chain may already be configured in the wallet.
          }
        }

        switchChain({ chainId: LOCALHOST_CHAIN_ID });
      } catch (error) {
        console.error("[AomiAdapterProvider] Failed to switch localhost:", error);
      }
    })();
  }, [chainId, connector, isConnected, switchChain]);

  return <>{children}</>;
}

function ParaAdapterBridge({ children }: { children: ReactNode }) {
  const coreStore = useContext(CoreStoreContext);
  const para = useClient();
  const { openModal } = useModal();
  const paraAccount = useParaAccount();
  const { address: wagmiAddress, chainId, isConnected: wagmiConnected } =
    useAccount();
  const { sendTransactionAsync } = useSendTransaction();
  const { signTypedDataAsync } = useSignTypedData();
  const { switchChainAsync, isPending: isSwitchingChain } = useSwitchChain();

  const embeddedPrimary =
    paraAccount.embedded.email ??
    paraAccount.embedded.farcasterUsername ??
    paraAccount.embedded.telegramUserId ??
    undefined;
  const embeddedWallet = paraAccount.embedded.wallets?.[0] as
    | { address?: string }
    | undefined;
  const embeddedAddress = embeddedWallet?.address;
  const externalAddress = paraAccount.external.evm?.address;
  const address = wagmiAddress ?? externalAddress ?? embeddedAddress;
  const authProvider = inferAuthProvider(paraAccount.embedded.authMethods);
  const providerLabel = formatAuthProvider(authProvider);
  const isConnected = Boolean(paraAccount.isConnected || wagmiConnected);

  const identity = useMemo<AccountIdentity>(() => {
    if (isConnected && embeddedPrimary) {
      return {
        kind: "social",
        isConnected,
        address,
        chainId: chainId ?? undefined,
        authProvider,
        primaryLabel: embeddedPrimary,
        secondaryLabel: providerLabel,
      };
    }

    if (isConnected && address) {
      return {
        kind: "wallet",
        isConnected,
        address,
        chainId: chainId ?? undefined,
        authProvider,
        primaryLabel: formatAddress(address) ?? "Connected wallet",
      };
    }

    return {
      ...DISCONNECTED_ADAPTER.identity,
      chainId: chainId ?? undefined,
    };
  }, [address, authProvider, chainId, embeddedPrimary, isConnected, providerLabel]);

  const adapter = useMemo<AomiAdapter>(() => {
    return {
      identity,
      isReady: Boolean(coreStore && para),
      isSwitchingChain,
      canConnect: Boolean(para),
      canManageAccount: identity.isConnected && Boolean(para),
      connect: async () => {
        if (!para) return;
        openModal({ step: "AUTH_MAIN" });
      },
      manageAccount: async () => {
        if (!para) return;
        openModal({ step: "ACCOUNT_MAIN" });
      },
      switchChain: switchChainAsync
        ? async (nextChainId: number) => {
            await switchChainAsync({ chainId: nextChainId });
          }
        : undefined,
      sendTransaction: sendTransactionAsync
        ? async (payload: WalletTxPayload) => {
            if (
              payload.chainId &&
              payload.chainId !== chainId &&
              switchChainAsync
            ) {
              await switchChainAsync({ chainId: payload.chainId });
            }

            const txHash = await sendTransactionAsync({
              to: payload.to as `0x${string}`,
              value: payload.value ? BigInt(payload.value) : undefined,
              data:
                payload.data && payload.data !== "0x"
                  ? (payload.data as `0x${string}`)
                  : undefined,
            });

            return {
              txHash,
              amount: payload.value,
            };
          }
        : undefined,
      signTypedData: signTypedDataAsync
        ? async (payload: WalletEip712Payload) => {
            const signArgs = toViemSignTypedDataArgs(payload);
            if (!signArgs) {
              throw new Error("Missing typed_data payload");
            }

            const requestChainId = parseChainId(signArgs.domain?.chainId);
            if (
              requestChainId &&
              requestChainId !== chainId &&
              switchChainAsync
            ) {
              await switchChainAsync({ chainId: requestChainId });
            }

            const signature = await signTypedDataAsync(signArgs as never);
            return { signature };
          }
        : undefined,
    };
  }, [
    chainId,
    coreStore,
    identity,
    isSwitchingChain,
    openModal,
    para,
    sendTransactionAsync,
    signTypedDataAsync,
    switchChainAsync,
  ]);

  return (
    <AomiAdapterContext.Provider value={adapter}>
      {children}
    </AomiAdapterContext.Provider>
  );
}

function InternalParaAomiAdapterProvider({
  children,
}: {
  children: ReactNode;
}) {
  const [queryClient] = useState(() => new QueryClient());
  const wallets = walletConnectProjectId
    ? externalWallets
    : externalWallets.filter((wallet) => wallet !== "WALLETCONNECT");
  const wagmiProjectId =
    walletConnectProjectId ?? "missing-walletconnect-project-id";

  const [paraClient] = useState<ParaWeb | null>(() => {
    if (typeof window === "undefined" || !paraApiKey) return null;
    return new ParaWeb(paraEnvironment, paraApiKey);
  });

  const [wagmiConfig] = useState(() => {
    if (!paraClient) return null;
    return createParaWagmiConfig(paraClient, {
      appName: "Aomi Labs",
      appDescription: "AI-powered blockchain operations assistant",
      appUrl:
        typeof window !== "undefined" ? window.location.origin : "https://aomi.dev",
      wallets,
      projectId: wagmiProjectId,
      chains: networks,
      transports,
      ssr: true,
    });
  });

  const inner = (
    <WagmiProvider config={wagmiConfig ?? ssrFallbackConfig}>
      <LocalhostNetworkEnforcer>
        {paraClient ? (
          <ParaAdapterBridge>{children}</ParaAdapterBridge>
        ) : (
          <AomiAdapterContext.Provider value={DISCONNECTED_ADAPTER}>
            {children}
          </AomiAdapterContext.Provider>
        )}
      </LocalhostNetworkEnforcer>
    </WagmiProvider>
  );

  return (
    <QueryClientProvider client={queryClient}>
      {paraClient ? (
        <ParaProvider
          paraClientConfig={paraClient}
          config={{
            appName: "Aomi Labs",
          }}
          paraModalConfig={{
            disableEmailLogin: true,
            oAuthMethods,
          }}
          externalWalletConfig={{
            appDescription: "AI-powered blockchain operations assistant",
            appUrl:
              typeof window !== "undefined" ? window.location.origin : "https://aomi.dev",
            appIcon: "/assets/images/aomi-logo.svg",
            wallets,
            ...(walletConnectProjectId
              ? {
                  walletConnect: {
                    projectId: walletConnectProjectId,
                  },
                }
              : {}),
            evmConnector: {
              config: {
                chains: networks,
                transports,
                ssr: true,
              },
            },
          }}
        >
          {inner}
        </ParaProvider>
      ) : (
        inner
      )}
    </QueryClientProvider>
  );
}

export function AomiAdapterProvider({
  children,
  adapter,
}: AomiAdapterProviderProps) {
  if (adapter) {
    return (
      <AomiAdapterContext.Provider value={adapter}>
        {children}
      </AomiAdapterContext.Provider>
    );
  }

  if (adapter === null) {
    return (
      <AomiAdapterContext.Provider value={DISCONNECTED_ADAPTER}>
        {children}
      </AomiAdapterContext.Provider>
    );
  }

  return <InternalParaAomiAdapterProvider>{children}</InternalParaAomiAdapterProvider>;
}

export function useAomiAdapter(): AomiAdapter {
  return useContext(AomiAdapterContext);
}

"use client";

